"use client";

import React, { useState } from "react";
import { motion } from "framer-motion";
import { ArrowRight, Zap, Sparkles } from "lucide-react";

interface InteractiveCardProps {
  title: string;
  description: string;
  onClick?: () => void;
  className?: string;
}

const InteractiveCard: React.FC<InteractiveCardProps> = ({
  title,
  description,
  onClick,
  className = ""
}) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isPressed, setIsPressed] = useState(false);

  return (
    <motion.div
      className={`relative bg-white rounded-2xl shadow-lg p-6 cursor-pointer border border-slate-200 overflow-hidden ${className}`}
      initial={{ opacity: 0, y: 30, scale: 0.95 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      whileHover={{ 
        y: -12,
        scale: 1.03,
        boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.25)",
        transition: { duration: 0.3, ease: "easeOut" }
      }}
      whileTap={{ scale: 0.97, y: -2 }}
      onHoverStart={() => setIsHovered(true)}
      onHoverEnd={() => setIsHovered(false)}
      onTapStart={() => setIsPressed(true)}
      onTap={() => setIsPressed(false)}
      onTapCancel={() => setIsPressed(false)}
      onClick={onClick}
    >
      {/* Animated background gradient */}
      <motion.div
        className="absolute inset-0 bg-gradient-to-br from-blue-500/5 via-purple-500/5 to-pink-500/5 opacity-0"
        animate={{ opacity: isHovered ? 1 : 0 }}
        transition={{ duration: 0.3 }}
      />

      {/* Floating particles */}
      <AnimatePresence>
        {isHovered && (
          <>
            <motion.div
              initial={{ opacity: 0, scale: 0 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0 }}
              className="absolute top-4 right-4 w-2 h-2 bg-blue-500 rounded-full"
              transition={{ delay: 0.1 }}
            />
            <motion.div
              initial={{ opacity: 0, scale: 0 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0 }}
              className="absolute bottom-4 left-4 w-1.5 h-1.5 bg-purple-500 rounded-full"
              transition={{ delay: 0.2 }}
            />
            <motion.div
              initial={{ opacity: 0, scale: 0 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0 }}
              className="absolute top-8 left-8 w-1 h-1 bg-pink-500 rounded-full"
              transition={{ delay: 0.3 }}
            />
          </>
        )}
      </AnimatePresence>

      {/* Icon container with magnetic effect */}
      <motion.div
        className="relative mb-4"
        animate={{
          rotate: isHovered ? [0, -5, 5, 0] : 0,
        }}
        transition={{ duration: 0.5, ease: "easeInOut" }}
      >
        <motion.div
          className="w-14 h-14 bg-gradient-to-br from-blue-500 to-purple-500 rounded-xl flex items-center justify-center text-white shadow-lg"
          animate={{
            rotate: isHovered ? 360 : 0,
            scale: isPressed ? 0.9 : isHovered ? 1.1 : 1
          }}
          transition={{ duration: 0.4, ease: "easeInOut" }}
        >
          <motion.div
            animate={{
              opacity: isHovered ? 0 : 1,
              scale: isHovered ? 0 : 1
            }}
            transition={{ duration: 0.2 }}
          >
            <Zap className="w-6 h-6" />
          </motion.div>
          <motion.div
            className="absolute"
            animate={{
              opacity: isHovered ? 1 : 0,
              scale: isHovered ? 1 : 0,
              rotate: isHovered ? -360 : 0
            }}
            transition={{ duration: 0.3, delay: 0.1 }}
          >
            <Sparkles className="w-6 h-6" />
          </motion.div>
        </motion.div>

        {/* Ripple effect */}
        {isHovered && (
          <motion.div
            className="absolute inset-0 bg-gradient-to-br from-blue-500 to-purple-500 rounded-xl"
            initial={{ scale: 1, opacity: 0.3 }}
            animate={{ scale: 1.5, opacity: 0 }}
            transition={{ duration: 0.6, ease: "easeOut" }}
            style={{ originX: 0.5, originY: 0.5 }}
          />
        )}
      </motion.div>

      {/* Content with staggered animation */}
      <div className="relative z-10">
        <motion.h3
          className="text-xl font-bold text-slate-900 mb-2"
          animate={{
            x: isHovered ? 4 : 0,
            color: isHovered ? "#3b82f6" : "#1e293b"
          }}
          transition={{ duration: 0.3, ease: "easeOut" }}
        >
          {title}
        </motion.h3>

        <motion.p
          className="text-slate-600 text-sm leading-relaxed"
          animate={{
            opacity: isHovered ? 0.8 : 1,
          }}
          transition={{ duration: 0.3 }}
        >
          {description}
        </motion.p>
      </div>

      {/* Arrow indicator */}
      <motion.div
        className="absolute bottom-6 right-6"
        animate={{
          x: isHovered ? 8 : 0,
          opacity: isHovered ? 1 : 0.5
        }}
        transition={{ duration: 0.3, ease: "easeOut" }}
      >
        <ArrowRight className="w-5 h-5 text-blue-500" />
      </motion.div>

      {/* Subtle border glow */}
      <motion.div
        className="absolute inset-0 rounded-2xl border-2 border-blue-500 opacity-0 pointer-events-none"
        animate={{ opacity: isHovered ? 0.3 : 0 }}
        transition={{ duration: 0.3 }}
      />
    </motion.div>
  );
};

export default InteractiveCard;

