"use client";

import React from "react";
import { motion, AnimatePresence } from "framer-motion";
import { CheckCircle, AlertCircle, Info, X, Sparkles } from "lucide-react";

type NotificationType = "success" | "error" | "info";

interface NotificationCardProps {
  type: NotificationType;
  title: string;
  message: string;
  onClose?: () => void;
  className?: string;
}

const NotificationCard: React.FC<NotificationCardProps> = ({
  type,
  title,
  message,
  onClose,
  className = ""
}) => {
  const [isVisible, setIsVisible] = React.useState(true);

  const typeConfig = {
    success: {
      bg: "bg-emerald-50 border-emerald-200",
      icon: <CheckCircle className="w-5 h-5 text-emerald-600" />,
      titleColor: "text-emerald-900",
      messageColor: "text-emerald-700",
      glowColor: "rgba(16, 185, 129, 0.25)",
      particleColor: "bg-emerald-400"
    },
    error: {
      bg: "bg-red-50 border-red-200",
      icon: <AlertCircle className="w-5 h-5 text-red-600" />,
      titleColor: "text-red-900",
      messageColor: "text-red-700",
      glowColor: "rgba(239, 68, 68, 0.25)",
      particleColor: "bg-red-400"
    },
    info: {
      bg: "bg-blue-50 border-blue-200",
      icon: <Info className="w-5 h-5 text-blue-600" />,
      titleColor: "text-blue-900",
      messageColor: "text-blue-700",
      glowColor: "rgba(59, 130, 246, 0.25)",
      particleColor: "bg-blue-400"
    }
  };

  const config = typeConfig[type];

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(() => onClose?.(), 300);
  };

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          className={`relative rounded-2xl border p-5 shadow-lg overflow-hidden ${config.bg} ${className}`}
          initial={{ opacity: 0, y: -50, scale: 0.9 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: -50, scale: 0.9 }}
          transition={{ duration: 0.3, ease: "easeOut" }}
          whileHover={{ scale: 1.02, boxShadow: "0 20px 40px -12px rgba(0,0,0,0.15), 0 0 20px rgba(0,0,0,0.05)" }}
        >
          <div className="flex items-start gap-4 relative z-10">
            <motion.div
              className="flex-shrink-0 relative"
              animate={{ scale: [1, 1.1, 1] }}
              transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
            >
              <div
                className={`w-10 h-10 rounded-full flex items-center justify-center ${
                  type === "success"
                    ? "bg-emerald-100"
                    : type === "error"
                    ? "bg-red-100"
                    : "bg-blue-100"
                }`}
              >
                {config.icon}
              </div>
            </motion.div>

            <div className="flex-1 min-w-0">
              <motion.h4
                className={`font-semibold ${config.titleColor} mb-1`}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.1, duration: 0.3 }}
              >
                {title}
              </motion.h4>

              <motion.p
                className={`text-sm ${config.messageColor} leading-relaxed`}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.2, duration: 0.3 }}
              >
                {message}
              </motion.p>
            </div>

            {onClose && (
              <motion.button
                onClick={handleClose}
                className="flex-shrink-0 text-slate-400 hover:text-slate-600 transition-colors p-1 rounded-lg hover:bg-slate-200/50"
                whileHover={{ scale: 1.1, rotate: 90 }}
                whileTap={{ scale: 0.9 }}
                transition={{ duration: 0.2 }}
              >
                <X className="w-4 h-4" />
              </motion.button>
            )}
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default NotificationCard;

