"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Star, ShoppingCart, Heart, Eye, Zap, Shield } from "lucide-react";

interface ProductCardProps {
  title: string;
  price: string;
  image: string;
  rating?: number;
  originalPrice?: string;
  badge?: string;
  features?: string[];
  className?: string;
}

const ProductCard: React.FC<ProductCardProps> = ({
  title,
  price,
  image,
  rating = 0,
  originalPrice,
  badge,
  features = [],
  className = ""
}) => {
  const [isLiked, setIsLiked] = useState(false);
  const [isHovered, setIsHovered] = useState(false);

  const renderStars = (rating: number) => {
    return Array.from({ length: 5 }).map((_, i) => (
      <motion.div
        key={i}
        initial={{ opacity: 0, rotate: -180, scale: 0 }}
        animate={{ opacity: 1, rotate: 0, scale: 1 }}
        transition={{
          delay: 0.6 + i * 0.1,
          duration: 0.5,
          ease: "backOut"
        }}
      >
        <Star 
          className={`w-4 h-4 transition-colors duration-300 ${
            i < Math.floor(rating) 
              ? "fill-yellow-400 text-yellow-400" 
              : i < rating 
              ? "fill-yellow-200 text-yellow-400" 
              : "text-slate-300"
          }`} 
        />
      </motion.div>
    ));
  };

  return (
    <motion.div
      className={`relative bg-white rounded-2xl shadow-lg overflow-hidden group ${className}`}
      initial={{ opacity: 0, y: 30, scale: 0.95 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      whileHover={{ 
        y: -12,
        scale: 1.02,
        boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.2)",
        transition: { duration: 0.3, ease: "easeOut" }
      }}
      onHoverStart={() => setIsHovered(true)}
      onHoverEnd={() => setIsHovered(false)}
    >
      {/* Image container with sophisticated effects */}
      <div className="relative">
        <motion.div
          className="aspect-square overflow-hidden bg-gradient-to-br from-purple-100 to-pink-100"
          whileHover={{ scale: 1.05 }}
          transition={{ duration: 0.5, ease: "easeOut" }}
        >
          <motion.img
            src={image}
            alt={title}
            className="w-full h-full object-cover"
            whileHover={{ scale: 1.1 }}
            transition={{ duration: 0.5, ease: "easeOut" }}
          />
        </motion.div>

        {/* Badge with animation */}
        {badge && (
          <motion.div
            className="absolute top-3 left-3 bg-red-500 text-white text-xs font-bold px-3 py-1.5 rounded-lg shadow-lg"
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.2, duration: 0.3 }}
            whileHover={{
              scale: 1.1,
              backgroundColor: "#dc2626"
            }}
          >
            <motion.div
              animate={{
                scale: [1, 1.05, 1]
              }}
              transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
            >
              {badge}
            </motion.div>
          </motion.div>
        )}

        {/* Quick view button */}
        <AnimatePresence>
          {isHovered && (
            <motion.button
              className="absolute top-3 right-3 w-10 h-10 bg-white/90 backdrop-blur-sm rounded-full flex items-center justify-center shadow-lg hover:bg-white transition-colors"
              initial={{ opacity: 0, scale: 0, rotate: -180 }}
              animate={{ opacity: 1, scale: 1, rotate: 0 }}
              exit={{ opacity: 0, scale: 0, rotate: 180 }}
              transition={{ duration: 0.3 }}
              whileHover={{ scale: 1.1, rotate: 90 }}
              whileTap={{ scale: 0.9 }}
            >
              <Eye className="w-4 h-4 text-slate-600" />
            </motion.button>
          )}
        </AnimatePresence>

        {/* Like button */}
        <motion.button
          onClick={() => setIsLiked(!isLiked)}
          className="absolute bottom-3 right-3 w-10 h-10 bg-white/90 backdrop-blur-sm rounded-full flex items-center justify-center shadow-lg hover:bg-white transition-colors z-10"
          whileHover={{ scale: 1.1, rotate: isLiked ? 360 : 0 }}
          whileTap={{ scale: 0.9 }}
          transition={{ duration: 0.3 }}
        >
          <motion.div
            animate={{
              scale: isLiked ? [1, 1.2, 1] : 1
            }}
            transition={{ duration: 0.3 }}
          >
            <Heart className={`w-4 h-4 transition-colors duration-300 ${
              isLiked ? "fill-red-500 text-red-500" : "text-slate-600"
            }`} />
          </motion.div>
        </motion.button>

        {/* Floating particles */}
        <motion.div
          className="absolute top-1/2 left-1/2 w-3 h-3 bg-purple-400 rounded-full opacity-60"
          animate={{
            scale: [1, 1.5, 1],
            opacity: [0.6, 1, 0.6],
            x: [0, 20, 0],
            y: [0, -20, 0]
          }}
          transition={{ duration: 3, repeat: Infinity, ease: "easeInOut" }}
        />
      </div>

      {/* Content section */}
      <motion.div
        className="p-4"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.3, duration: 0.5 }}
      >
        <motion.h3
          className="font-semibold text-slate-900 mb-2 line-clamp-2"
          whileHover={{ color: "#a855f7" }}
          transition={{ duration: 0.2 }}
        >
          {title}
        </motion.h3>

        {/* Rating */}
        <div className="flex items-center gap-2 mb-3">
          <div className="flex gap-1">
            {renderStars(rating)}
          </div>
          <span className="text-sm text-slate-600">({rating})</span>
        </div>

        {/* Features */}
        {features.length > 0 && (
          <motion.div
            className="space-y-1 mb-3"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.5, duration: 0.3 }}
          >
            {features.slice(0, 2).map((feature, index) => (
              <motion.div
                key={index}
                className="flex items-center gap-1.5 text-xs text-slate-600"
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.6 + index * 0.1, duration: 0.3 }}
              >
                <div className="w-1 h-1 bg-purple-400 rounded-full" />
                <span>{feature}</span>
              </motion.div>
            ))}
          </motion.div>
        )}

        {/* Price */}
        <div className="flex items-center gap-2 mb-4">
          <motion.span
            className="text-xl font-bold text-slate-900"
            animate={{
              color: isHovered ? "#a855f7" : "#1e293b"
            }}
            transition={{ duration: 0.2 }}
          >
            {price}
          </motion.span>
          {originalPrice && (
            <motion.span
              className="text-sm text-slate-500 line-through"
              animate={{
                opacity: isHovered ? 0.5 : 1
              }}
              transition={{ duration: 0.2 }}
            >
              {originalPrice}
            </motion.span>
          )}
        </div>

        {/* Add to cart button */}
        <motion.button
          className="w-full bg-gradient-to-r from-purple-600 to-pink-600 text-white py-2.5 px-4 rounded-xl font-semibold hover:from-purple-700 hover:to-pink-700 transition-all duration-300 flex items-center justify-center gap-2 group"
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          transition={{ duration: 0.2 }}
        >
          <motion.div
            animate={{
              rotate: [0, 5, -5, 0]
            }}
            transition={{ duration: 3, repeat: Infinity, ease: "easeInOut" }}
          >
            <ShoppingCart className="w-4 h-4" />
          </motion.div>
          <span>Add to Cart</span>
          <motion.div
            className="opacity-0 group-hover:opacity-100 transition-opacity duration-300"
            animate={{
              x: [0, 4]
            }}
            transition={{ duration: 0.3 }}
          >
            →
          </motion.div>
        </motion.button>
      </motion.div>

      {/* Subtle border glow */}
      <motion.div
        className="absolute inset-0 rounded-2xl border-2 border-purple-500 opacity-0 pointer-events-none"
        whileHover={{ opacity: 0.3 }}
        transition={{ duration: 0.3 }}
      />
    </motion.div>
  );
};

export default ProductCard;

