"use client";

import React from "react";
import { motion } from "framer-motion";
import { TrendingUp, TrendingDown, Activity, BarChart3, ArrowUp, ArrowDown } from "lucide-react";

interface DashboardCardProps {
  title: string;
  value: string;
  chartData: number[];
  change?: string;
  isPositive?: boolean;
  trend?: "up" | "down" | "stable";
  className?: string;
}

const DashboardCard: React.FC<DashboardCardProps> = ({
  title,
  value,
  chartData,
  change,
  isPositive = true,
  trend = "stable",
  className = ""
}) => {
  const max = Math.max(...chartData);
  const min = Math.min(...chartData);
  const range = max - min || 1;

  return (
    <motion.div
      className={`relative bg-white rounded-2xl shadow-lg p-6 border border-slate-200 overflow-hidden ${className}`}
      initial={{ opacity: 0, y: 30, scale: 0.95 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      whileHover={{ 
        y: -8,
        scale: 1.02,
        boxShadow: "0 20px 40px -12px rgba(0, 0, 0, 0.15)",
        transition: { duration: 0.3, ease: "easeOut" }
      }}
    >
      {/* Animated background pattern */}
      <motion.div
        className="absolute inset-0 opacity-0"
        whileHover={{ opacity: 1 }}
        transition={{ duration: 0.3 }}
      >
        <div className="absolute inset-0 bg-gradient-to-br from-blue-50 via-purple-50 to-indigo-50" />
        <motion.div
          className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 rounded-full blur-2xl"
          animate={{
            scale: [1, 1.2, 1],
            opacity: [0.3, 0.6, 0.3]
          }}
          transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
        />
      </motion.div>

      <div className="relative z-10">
        {/* Header with icon and trend */}
        <motion.div
          className="flex items-center justify-between mb-6"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.1 }}
        >
          <div className="flex items-center gap-3">
            <motion.div
              className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                isPositive ? "bg-emerald-100" : "bg-red-100"
              }`}
              animate={{
                rotate: trend === "up" ? [0, 5, -5, 0] : trend === "down" ? [0, -5, 5, 0] : [0, 2, -2, 0],
                scale: [1, 1.05, 1]
              }}
              transition={{ duration: 3, repeat: Infinity, ease: "easeInOut" }}
            >
              {trend === "up" ? (
                <ArrowUp className="w-5 h-5 text-emerald-600" />
              ) : trend === "down" ? (
                <ArrowDown className="w-5 h-5 text-red-600" />
              ) : (
                <Activity className="w-5 h-5 text-blue-600" />
              )}
            </motion.div>
            <h3 className="text-sm font-medium text-slate-600">{title}</h3>
          </div>

          {/* Change indicator */}
          {change && (
            <motion.div
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-semibold ${
                isPositive 
                  ? "bg-emerald-100 text-emerald-700 border border-emerald-200" 
                  : "bg-red-100 text-red-700 border border-red-200"
              }`}
              animate={{
                scale: [1, 1.05, 1],
              }}
              transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
            >
              {isPositive ? (
                <TrendingUp className="w-3.5 h-3.5" />
              ) : (
                <TrendingDown className="w-3.5 h-3.5" />
              )}
              {change}
            </motion.div>
          )}
        </motion.div>

        {/* Main value with counter animation */}
        <motion.div
          className="relative mb-6"
        >
          <motion.p
            className="text-3xl font-bold text-slate-900"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2, duration: 0.5 }}
          >
            {value}
          </motion.p>

          {/* Decorative elements */}
          <motion.div
            className="absolute -top-2 -right-2 w-8 h-8 opacity-20"
            animate={{
              rotate: [0, 180],
              scale: [1, 1.2, 1]
            }}
            transition={{ duration: 8, repeat: Infinity, ease: "linear" }}
          >
            <BarChart3 className="w-full h-full text-slate-400" />
          </motion.div>
        </motion.div>

        {/* Enhanced chart visualization */}
        <motion.div
          className="relative"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3, duration: 0.5 }}
        >
          <div className="flex items-end gap-1.5 h-20">
            {chartData.map((value, index) => (
              <motion.div
                key={index}
                className={`flex-1 rounded-t-sm ${
                  isPositive ? "bg-gradient-to-t from-emerald-500 to-emerald-300" : "bg-gradient-to-t from-red-500 to-red-300"
                }`}
                style={{ height: "100%" }}
                initial={{ scaleY: 0 }}
                animate={{ scaleY: value / max }}
                transition={{
                  delay: 0.4 + index * 0.05,
                  duration: 0.6,
                  ease: "easeOut"
                }}
                whileHover={{
                  scaleY: value / max * 1.1,
                  transition: { duration: 0.2 }
                }}
              >
                {/* Animated glow effect on hover */}
                <motion.div
                  className="absolute inset-0 bg-white/20 rounded-t-sm opacity-0"
                  whileHover={{ opacity: 1 }}
                  transition={{ duration: 0.2 }}
                />
              </motion.div>
            ))}
          </div>

          {/* Chart baseline */}
          <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-slate-200" />
        </motion.div>

        {/* Trend indicator dots */}
        <motion.div
          className="flex items-center gap-2 mt-4"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.6, duration: 0.3 }}
          >
            {[...Array(3)].map((_, i) => (
              <motion.div
                key={i}
                className={`w-1.5 h-1.5 rounded-full ${
                  isPositive ? "bg-emerald-400" : "bg-red-400"
                }`}
                animate={{
                  scale: [1, 1.5, 1],
                  opacity: [0.4, 1, 0.4]
                }}
                transition={{
                  duration: 2,
                  repeat: Infinity,
                  ease: "easeInOut",
                  delay: i * 0.2
                }}
              />
            ))}
          </motion.div>

        {/* Pulse indicator */}
        <motion.div
          className={`absolute bottom-4 right-4 w-2 h-2 rounded-full ${
            isPositive ? "bg-emerald-500" : "bg-red-500"
          }`}
          animate={{
            scale: [1, 1.5, 1],
            opacity: [1, 0.5, 1]
          }}
          transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
        />
      </div>

      {/* Subtle border animation */}
      <motion.div
        className={`absolute inset-0 rounded-2xl border-2 opacity-0 pointer-events-none ${
          isPositive ? "border-emerald-500" : "border-red-500"
        }`}
        whileHover={{ opacity: 0.3 }}
        transition={{ duration: 0.3 }}
      />
    </motion.div>
  );
};

export default DashboardCard;

